class Solution:
    def largestWordCount(self, messages, senders):
        totals = {}
        for msg, snd in zip(messages, senders):
            totals[snd] = totals.get(snd, 0) + len(msg.split(' '))
        best_name = ''
        best_count = -1
        for name in sorted(totals.keys()):
            cnt = totals[name]
            if cnt > best_count or (cnt == best_count and name > best_name):
                best_count = cnt
                best_name = name
        return best_name

